  ngOnInit(): void {
    this.accountId = this.ls.getItem('accountId');
    let overdraftStatus = this.ls.getItem('overDraftByStatus') || null;
    console.log("fetch",overdraftStatus);
    this.overDraftByStatus = overdraftStatus != null ? overdraftStatus.isActive : false; 
    console.log(this.overDraftByStatus);
    let isScoreCardScreen: boolean = JSON.parse(this.ls.getItem('ASSESSMENT_QA_DONE'));
    this.accountType = this.ls.getItem('accountType');
    this.loggedInUser = this.ls.getItem('ICUST_USER');
    this.isQualitative = localStorage.getItem('Status');
    this.no_of_applicants = this.ls.getItem('NO_OF_APPLICANTS');
    console.log(this.no_of_applicants);
    console.log(this.loggedInUser);
    this.accountType == "current" ? this.accountType = "saving" : this.accountType = "saving";//This line because we have backend data only for savings. This line is temporary.
    
    this.urlService.previousUrl$
      .subscribe((previousUrl: string) => {
        this.previousUrl = previousUrl
      });

    if (this.accountId != null && isScoreCardScreen) {
      this.showEditOption = true;
      this.isQualitativeScreen = true;
      this.getAllQualitative();
    } else {
      this.showEditOption = false;
      this.loadData();
    }

  }
