            this.sbMultiSelectAnswer.push(scAns[m]);
            //  this.sbMultiSelectAnswer[this.qualitativeScoreboardSummary.icustScorecardMapping[i].scoreCardQuestionId].selectedAnswer.push(scAns[m]);
