    //     this.scoreCardMappingArray[i].scorecardAnswer = answer;
    //     dataUpdated = true;
    //   }
    // }
    // if (!dataUpdated) {
    //   let dataOject: any = {};
    //   dataOject.scoreCardQuestionId = id;
    //   dataOject.scorecardAnswer = answer;
    //   if (mapId != null) {
    //     dataOject.scoreCardMappingId = mapId;

    //   }
    //   this.scoreCardMappingArray.push(dataOject);
    //   // console.log(dataOject,"Dataobject");
    // }
    // if (this.scoreCardMappingArray.length == this.scoreboardQuestionsArray.length) {
    //   let disableDoneBtn: number = 0;
    //   for (let i = 0; i < this.scoreCardMappingArray.length; i++) {
    //     let answerIs: any = this.scoreCardMappingArray[i].scorecardAnswer;
    //     if (answerIs == '' || answerIs == null || answerIs == undefined) {
