import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { FormGroup, FormControl, FormArray, FormBuilder } from '@angular/forms';
import { MatSnackBar } from '@angular/material/snack-bar';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from 'app/shared/services/api.service';
import { DataService } from 'app/shared/services/data.service';
import { LocalStoreService } from 'app/shared/services/local-store.service';
import { AccountService } from '../../account.service';
import { flow } from 'lodash';
import { flatMap, filter } from 'lodash/fp';
import { UrlService } from '../../url.service';

@Component({
  selector: 'app-account-service',
  templateUrl: './account-service.component.html',
  styleUrls: ['./account-service.component.scss']
})
export class AccountServiceComponent implements OnInit {
  show: boolean = false;
  selectedRow= false;
  // selection = new SelectionModel<PeriodicElement>(true, []);
  accountServiceForm: FormGroup;
  statementList = [
    {
      "id": 1,
      "name": "EMAIL",
      "checked": false
    },
    {
      "id": 2,
      "name": "POST",
      "checked": false
    }
  ];
  bankList = [
    {
      "id": 1,
      "name": "Phone Banking",
      "checked": false
    },
    {
      "id": 2,
      "name": "Kiosk Banking",
      "checked": false
    },
    {
      "id": 3,
      "name": "Direct Banking",
      "checked": false
    }
  ];
  communicationList = [
    {
      "id": 1,
      "name": "EMAIL",
      "checked": false
    },
    {
      "id": 2,
      "name": "POST",
      "checked": false
    },
    {
      "id": 3,
      "name": "SMS",
      "checked": false
    }
  ];
  bankChannelPreferencesArray : any[] = [];
  commChannelPreferencesArray : any[] = [];
  AccStatementPreferenceArray : any[] = [];
  accountId: any;
  isNew: boolean;
  navSubscription: any;
  routeparams: any;
  showEditOption: boolean = false;
  previousUrl: string = '';
  enableFinish: boolean=false;
  statementFrncy: string;
  bankChanlPref: string;
  constructor(private router: Router, private urlService: UrlService, private dataService: DataService, private route: ActivatedRoute, private snack: MatSnackBar, private ls: LocalStoreService, private accountService: AccountService, private formBuilder: FormBuilder, private apiService: ApiService, private cdr:ChangeDetectorRef) { }

  ngOnInit(): void {
    this.accountId = this.ls.getItem('accountId');
    let isAccountServiceDone:boolean = JSON.parse(this.ls.getItem('ACC_SERVICE_DONE'));

    if(this.accountId != null && isAccountServiceDone){
      console.log("editform is true");
      this.showEditOption = true;
      this.gettingAccountService();
      // call api service and build data with response
    }else{
      this.showEditOption = false;
      this.buildServiceForm();
      console.log("editform is false");
      this.accountServiceForm.controls['statementPref'].patchValue(this.statementList);
      this.accountServiceForm.controls['commChannelPref'].patchValue(this.communicationList);
      // build form without data for capturing
    }
  
    console.log("showEditOption", this.showEditOption);
    this.urlService.previousUrl$
    .subscribe((previousUrl: string) => {
        this.previousUrl = previousUrl
    });

  }

  gettingAccountService() {
    this.apiService.gettingAccountServiceDetails(this.accountId)
    .subscribe((resp: any) => {
      console.log("All Account Service", resp);
      this.buildServiceForm(resp);
      this.statementList = resp.statementPref;
      this.communicationList = resp.commChannelPref;
      this.bankList = resp.bankChannelPref
      // console.log("showEditOption", this.showEditOption);
      this.cdr.markForCheck();
      for(var i =0 ;i< this.bankList.length;i++){
      
        if(this.bankList[i].checked){
          this.bankChannelPreferencesArray.push(this.bankList[i].name);
        }
      }

      for(var i =0 ;i< this.communicationList.length;i++){
      
        if(this.communicationList[i].checked){
          this.commChannelPreferencesArray.push(this.communicationList[i].name);
        }
      }
      for(var i =0 ;i< this.statementList.length;i++){
        if(this.statementList[i].checked){
          this.AccStatementPreferenceArray.push(this.statementList[i].name);
        }
      }
      
      localStorage.setItem('statementFrequency', resp.statementFrequency);
      this.enableFinish=true;
      // localStorage.setItem('bankChannelPref', resp.bankChannelPref);
    });
  }
  statementFrequency(e){
    this.statementFrncy=localStorage.getItem('statementFrequency');
    if(e!=this.statementFrncy){
      this.enableFinish=true;
    }
  }
  bankChannelPref(e){
    this.bankChanlPref=localStorage.getItem('bankChannelPref');
    if(e!=this.bankChanlPref){
      this.enableFinish=true;
    }
  }

  buildServiceForm(data?) {
    this.accountServiceForm = this.formBuilder.group({
      accServiceId: [data ? data.accServiceId : null],
      productAccountId: [this.accountId != null ? this.accountId : null],
      statementFrequency: [data ? data.statementFrequency : ''],
      statementPref: [data ? this.flattenValues(data.statementPref) : ''],
      bankChannelPref: [data ? data.bankChannelPref : ''],
      commChannelPref: [data ? this.flattenValues(data.commChannelPref) : ''],
      chequebookNeeded: [data ? data.chequebookNeeded : false],
      passbookNeeded: [data ? data.passbookNeeded : false]
    });
  }

  onChecklistChange(checked, checkbox) {
    checkbox.checked = checked;
    this.enableFinish=true;
    const checklist = this.accountServiceForm.get('statementPref');
    checklist.setValue(this.flattenValues(this.statementList));
    if(checked){
      this.AccStatementPreferenceArray.push(checkbox.name);
    }
    else{
      this.AccStatementPreferenceArray.forEach( (item, index) => {
        if(item === checkbox.name){
          this.AccStatementPreferenceArray.splice(index,1);
        }
      });
    }
  }

  onCheckComChange(checked, checkbox) {
    console.log(checked);
    console.log(checkbox);
    checkbox.checked = checked;
    const checklist = this.accountServiceForm.get('commChannelPref');
    checklist.setValue(this.flattenValues(this.communicationList));
    if(checked){
      this.commChannelPreferencesArray.push(checkbox.name);
      console.log("checked",checkbox.name);
      this.enableFinish=true;
    }
    else{
      this.commChannelPreferencesArray.forEach( (item, index) => {
        if(item === checkbox.name){
          this.commChannelPreferencesArray.splice(index,1);
          console.log("checked",checkbox.name);
          this.enableFinish=true;
        }
      });
    }
  }
  onCheckbankChange(checked, checkbox) {
    console.log(checked);
    console.log(checkbox);
    checkbox.checked = checked;
    const checklist = this.accountServiceForm.get('bankChannelPref');
    checklist.setValue(this.flattenValues(this.bankList));
    if(checked){
      this.bankChannelPreferencesArray.push(checkbox.name);
      console.log("checked",checkbox.name);
      this.enableFinish=true;
    }
    else{
      this.bankChannelPreferencesArray.forEach( (item, index) => {
        if(item === checkbox.name){
          this.bankChannelPreferencesArray.splice(index,1);
          console.log("checked",checkbox.name);
          this.enableFinish=true;
        }
      });
    }
  }

  flattenValues(checkboxes) {
    const flattenedValues = flow([
      filter(checkbox => checkbox.checked),
      flatMap(checkbox => checkbox.name)
    ])(checkboxes);
    return flattenedValues.join(',');
  }

  isObjectEmpty(value) {
    return (
      Object.prototype.toString.call(value) === '[object Object]' &&
      JSON.stringify(value) === '{}'
    );
  }

  togglePreference() {
    this.show = !this.show;
  }

  goBack() {
    this.router.navigate([this.previousUrl]);
  }

  onSubmit() {
  
    let accountPayload = {
      "productAccountId": this.accountId,
      "accServiceId":this.accountServiceForm.value.accServiceId,
      "statementFrequency": this.accountServiceForm.value.statementFrequency,
      "statementPref": this.statementList,
      "bankChannelPref" : this.bankList,
      "commChannelPref": this.communicationList,
      "chequebookNeeded": this.accountServiceForm.value.chequebookNeeded,
      "passbookNeeded": this.accountServiceForm.value.passbookNeeded
    };

    if (this.accountServiceForm.invalid) {
      return;
    }

    if (this.showEditOption) {
      this.apiService.updateAccountService(this.accountId, accountPayload)
        .subscribe((data: any) => {
          console.log(data);
          this.accountService.refresh.next();
          this.router.navigate([`/home/application/nominee/add/${this.accountId}`]);
          this.snack.open('Account Service Updated!', 'OK', { duration: 4000, verticalPosition: 'top', horizontalPosition: 'right' });
        }, err => {
          console.log(err);
        });
    } else {
      this.apiService.createAccountService(this.accountId, accountPayload)
        .subscribe((data: any) => {
          console.log(data);
          this.ls.setItem('ACC_SERVICE_DONE', true);
          this.accountService.refresh.next();
          this.router.navigate([`/home/application/nominee/add/${this.accountId}`]);
          this.snack.open('Account Service Saved!', 'OK', { duration: 4000, verticalPosition: 'top', horizontalPosition: 'right' });
        }, err => {
          console.log(err);
        });
    }
  }

  ngOnDestroy(): void {
  }

}